require('GameUtility')MJPai={}local a=GameUtility.E_MJPai;local b=GameUtility.ERule_Mode;function MJPai:Init(c)local d={}setmetatable(d,self)self.__index=self;d:Build(c)return d end;function MJPai:Build(c)self.index=-1;self.dora=false;self.type=nil;self.open=false;self.tianming=false;self.baida=false;self.str=c;if string.sub(c,1,1)=='0'then self.dora=true;self.index=5 else self.dora=false;self.index=tonumber(string.sub(c,1,1))end;local e=string.sub(c,2,2)if e=='z'then self.type=a.z elseif e=='m'then self.type=a.m elseif e=='s'then self.type=a.s elseif e=='p'then self.type=a.p end;if string.match(c,'[t]')then if DesktopMgr and DesktopMgr.Inst and DesktopMgr.Inst:is_tianming_mode()then self.tianming=true else self.open=true end end;if self.str=='bd'then self.type=a.bd;self.baida=true end end;function MJPai:IsZ()return self.type==a.z end;function MJPai:IsLaoTou()return not self:IsZ()and(self.index==1 or self.index==9)end;function MJPai:IsYao()return self:IsZ()or self:IsLaoTou()end;function MJPai:IsSiXi()return self:IsZ()and self.index>=1 and self.index<=4 end;function MJPai:IsSanYuan()return self:IsZ()and self.index>=5 and self.index<=7 end;function MJPai:Clone()return MJPai:Init(self.str)end;function MJPai:NumValue()local f=MJPai.GetNumValue(self.type,self.index)return f end;function MJPai:ToString()return self.str end;function MJPai.Create(string)return MJPai:Init(string)end;function MJPai.GetNumValue(e,g)local f=0;if e==a.m then f=g elseif e==a.p then f=g+10000 elseif e==a.s then f=g+10000*2 elseif e==a.z then f=g*10+10000*3 end;return f end;function MJPai.IsSame(h,i)return h.type==i.type and h.index==i.index and h.dora==i.dora and h.open==i.open and h.tianming==i.tianming end;function MJPai.Distance(h,i)return h:NumValue()-i:NumValue()end;function MJPai.DoraMet(h,j)if h.type~=j.type then return false end;local g=j.index+1;if DesktopMgr and DesktopMgr.Inst and DesktopMgr.Inst:is_field_spell_extra_dora()then if h.index==j.index then return true end end;if j:IsZ()then if j:IsSiXi()then if g==5 then g=1 end elseif j:IsSanYuan()then if g==8 then g=5 end end else if g==10 then g=1 end;if DesktopMgr and DesktopMgr.Inst and DesktopMgr.Inst.rule_mode==b.Liqi3 and j.type==a.m then if g==2 then g=9 end end end;return g==h.index end;function MJPai.AmuletDoraMet(h,j)if h.type~=j.type then return false end;local g=j.index+1;if j:IsZ()then if j:IsSiXi()then if g==5 then g=1 end elseif j:IsSanYuan()then if g==8 then g=5 end end else if g==10 then g=1 end;if j.type==a.m then if g==2 then g=9 end end end;return g==h.index end;function MJPai:TypeString()if self.type==a.m then return'm'elseif self.type==a.p then return'p'elseif self.type==a.s then return's'elseif self.type==a.z then return'z'end;return''end;return MJPai